<?php
function checkPerfectSquare($num) {
    // Input validation: Ensure the input is an integer
    if (!is_int($num)) {
        echo "Error: Please enter a valid integer.";
        return;
    }

    // Calculate the square root
    $sqrt = sqrt($num);

    // Check if the square root is an integer
    if (floor($sqrt) == $sqrt) {
        echo "$num is a perfect square!";
    } else {
        echo "$num is not a perfect square.";
    }
}

// Example usage:
$input = isset($_GET['number']) ? intval($_GET['number']) : 0;
